127.     /// <param name="formats">Formatting options controlling symbol vs name and scale.</param>
128.     /// <param name="decimals">Optional number of decimal places to round to.</param>
129.     /// <returns>A string with the metric representation (e.g., "1.5k" or "1.5 kilo").</returns>
130.     /// <example>
131.     /// <code>
132.     /// 1500.ToMetric() => "1.5k"
133.     /// 1500.ToMetric(MetricFormat.None) => "1.5 kilo"
134.     /// 2500000.ToMetric(MetricFormat.UseSymbol) => "2.5M"
135.     /// </code>
136.     /// </example>
137.     public static string ToMetric(this double input, MetricFormat formats = MetricFormat.UseSymbol, int? decimals = null)
138.     {
139.         if (double.IsNaN(input) || double.IsInfinity(input))
140.         {
141.             return input.ToString();
142.         }
143. 
144.         if (Math.Abs(input) < 1e-24)
145.         {
146.             return "0";
147.         }
148. 
149.         var isNegative = input < 0;
150.         input = Math.Abs(input);
151. 
152.         var exponent = (int)Math.Floor(Math.Log10(input));
153.         var metricExponent = exponent - (exponent % 3);
