158.             return isNegative ? $"-{formatted}" : formatted;
159.         }
160. 
161.         if (!ExponentToSymbol.TryGetValue(metricExponent, out var symbol))
162.         {
163.             var fallback = input.ToString("G");
164.             return isNegative ? $"-{fallback}" : fallback;
165.         }
166. 
167.         var scaledValue = input / PowersOf10[metricExponent];
168.         var valueStr = decimals.HasValue ? scaledValue.ToString($"F{decimals}") : scaledValue.ToString("G4");
169. 
170.         var suffix = formats.HasFlag(MetricFormat.UseSymbol)
171.             ? SymbolStrings[symbol]
172.             : $" {GetPrefixName(symbol, formats)}";
173. 
174.         return isNegative ? $"-{valueStr}{suffix}" : $"{valueStr}{suffix}";
175.     }
